      );
    } catch {
      redirect(
        `/admin/classes?error=${encodeURIComponent(
          "Failed to cancel class. Ensure there are no active future sessions."
        )}`
      );
    }

    redirect(`/admin/classes?status=class_cancelled&class_id=${encodeURIComponent(classId)}`);
  }

