                    Time <span className="text-red-600">*</span>
                  </label>
                  <input
                    id="time"
                    name="time"
                    type="time"
                    required
                    className="w-full rounded-lg border border-zinc-300 bg-white px-3 py-2 text-sm text-zinc-900"
                  />
                </div>
              </div>

              <div className="space-y-2">
                <label
                  htmlFor="quota_defined"
                  className="block text-sm font-medium text-zinc-900"
                >
                  Quota <span className="text-red-600">*</span>
                </label>
                <input
                  id="quota_defined"
                  name="quota_defined"
                  type="number"
                  required
                  min={1}
                  placeholder="e.g. 20"
                  className="w-full rounded-lg border border-zinc-300 bg-white px-3 py-2 text-sm text-zinc-900 placeholder:text-zinc-400"
                />
              </div>

              <div className="flex items-center justify-end gap-2">
                <button
                  type="button"
                  onClick={() => setOpen(false)}
                  className="rounded-lg border border-zinc-300 px-3 py-2 text-sm font-medium text-zinc-900 hover:bg-zinc-100"
                >
                  Cancel
                </button>
                <SubmitButton onComplete={() => setOpen(false)} />
              </div>
            </form>
          </div>
        </div>
      ) : null}
    </>
  );
}

function SubmitButton({ onComplete }: { onComplete: () => void }) {
  const { pending } = useFormStatus();

  useEffect(() => {
    if (!pending) {
      return;
    }
    onComplete();
  }, [pending, onComplete]);

  return (
    <button
      type="submit"
      disabled={pending}
      className="rounded-lg bg-zinc-900 px-3 py-2 text-sm font-medium text-white hover:bg-zinc-700 disabled:cursor-not-allowed disabled:bg-zinc-400"
    >
      {pending ? "Creating..." : "Create"}
    </button>
  );
}

"use client";

import { useFormStatus } from "react-dom";

type CancelClassButtonProps = {
  classId: string;
  submitAction: (formData: FormData) => void | Promise<void>;
};

export function CancelClassButton({
  classId,
  submitAction,
}: CancelClassButtonProps) {
  return (
    <form
      action={submitAction}
      onSubmit={(event) => {
        const confirmed = window.confirm(
          "Cancel this class? This will mark it as cancelled."
        );
        if (!confirmed) {
          event.preventDefault();
        }
      }}
    >
      <input type="hidden" name="class_id" value={classId} />
      <SubmitButton />
    </form>
  );
}

function SubmitButton() {
  const { pending } = useFormStatus();

  return (
    <button
      type="submit"
      disabled={pending}
      className="rounded-md border border-red-300 px-3 py-1.5 text-xs font-medium text-red-700 hover:bg-red-50 disabled:cursor-not-allowed disabled:border-zinc-300 disabled:text-zinc-400"
    >
      {pending ? "Cancelling..." : "Cancel"}
    </button>
  );
}

